import { useEffect, useRef, useState, useCallback } from "react";
import { RESUME_PDF, PROJECTS, SKILLS, LEARNING, SERVICES, CONTACTS, SOCIALS, MARQUEE, ABOUT, TESTIMONIALS } from "./config";

const WORDS = ["BUILDING","CRAFTING","DESIGNING","SHIPPING","LAUNCHING"];

function Loader({ onDone }: { onDone: () => void }) {
  const [pct, setPct] = useState(0);
  const [word, setWord] = useState("BUILDING");
  const start = useRef(performance.now());
  useEffect(() => {
    let raf: number;
    const tick = (now: number) => {
      const p = Math.min(Math.floor(((now - start.current) / 2200) * 100), 100);
      setPct(p); setWord(WORDS[Math.floor((p / 100) * WORDS.length) % WORDS.length]);
      if (p < 100) raf = requestAnimationFrame(tick); else setTimeout(onDone, 200);
    };
    raf = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(raf);
  }, [onDone]);
  return (
    <div style={{position:"fixed",inset:0,zIndex:9999,background:"#060606",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:20}}>
      <div style={{fontFamily:"'Instrument Serif',serif",fontStyle:"italic",fontSize:13,letterSpacing:6,textTransform:"uppercase",color:"rgba(240,237,232,0.28)",minHeight:18}}>{word}</div>
      <div style={{fontSize:"clamp(70px,12vw,140px)",fontWeight:800,letterSpacing:-6,lineHeight:1,color:"#f0ede8",fontVariantNumeric:"tabular-nums"}}>{String(pct).padStart(3,"0")}</div>
      <div style={{width:200,height:1,background:"rgba(255,255,255,0.07)",borderRadius:1}}>
        <div style={{height:"100%",background:"linear-gradient(90deg,#c8b89a,#8fafc8)",borderRadius:1,width:`${pct}%`,transition:"width 0.04s linear"}}/>
      </div>
    </div>
  );
}

