function WordReveal({dark}:{dark:boolean}){
  const [rev,setRev]=useState(false),ref=useRef<HTMLDivElement>(null),bdr=dark?"rgba(255,255,255,0.07)":"rgba(0,0,0,0.1)";
  const words="I build whatever you need — portfolio, invitation, SaaS product, business website. Give me a brief and I will turn it into a premium digital product.".split(" ");
  useEffect(()=>{const obs=new IntersectionObserver(e=>{if(e[0].isIntersecting){setRev(true);obs.disconnect();}},{threshold:0.15});if(ref.current)obs.observe(ref.current);return()=>obs.disconnect();},[]);
  return (
    <div ref={ref} style={{padding:"60px 56px",maxWidth:1280,margin:"0 auto",borderTop:`1px solid ${bdr}`,borderBottom:`1px solid ${bdr}`}}>
      <div style={{fontFamily:"'Instrument Serif',serif",fontStyle:"italic",fontSize:"clamp(18px,3vw,38px)",lineHeight:1.65}}>
        {words.map((w,i)=><span key={i} style={{display:"inline",marginRight:"0.28em",color:dark?"#f0ede8":"#18150f",opacity:rev?1:0.15,transition:`opacity 0.4s ease ${i*38}ms`}}>{w} </span>)}
      </div>
    </div>
  );
}

