  const onMM=(e:React.MouseEvent)=>{if(!isDragging.current)return;const dx=e.clientX-startX.current;dragDelta.current=Math.abs(dx);posRef.current=scrollLeft.current-dx;if(posRef.current<0)posRef.current+=LOOP_W;if(posRef.current>=LOOP_W)posRef.current-=LOOP_W;if(trackRef.current)trackRef.current.style.transform=`translateX(-${posRef.current}px)`;};
  const onMU=()=>{isDragging.current=false;};
  const ts=useRef(0);
