/* ── SINGLE COLUMN (scrolls up or down) ─────────────────────── */
function TestiColumn({dark,cards,direction,card,bdr,t2,loopLen,mobile=false}:{
  dark:boolean;
  cards:typeof TESTIMONIALS;
  direction:"up"|"down";
  card:string;bdr:string;t2:string;
  loopLen:number;
  mobile?:boolean;
}){
  const trackRef  = useRef<HTMLDivElement>(null);
  const pausedRef = useRef(false);
  const posRef    = useRef(0);
  const animRef   = useRef<number>(0);
  const SPEED     = direction==="up" ? 0.4 : -0.4;

  // measure total height of one loop
  const [loopH, setLoopH] = useState(0);
  useEffect(()=>{
    if(!trackRef.current) return;
    const measure = () => {
      if(trackRef.current && trackRef.current.scrollHeight > 0){
        setLoopH(trackRef.current.scrollHeight / (cards.length / loopLen));
      }
    };
    // Measure immediately and again after paint
    measure();
    const t1 = setTimeout(measure, 100);
    const t2 = setTimeout(measure, 500);
    // Also watch for size changes
    const ro = new ResizeObserver(measure);
    ro.observe(trackRef.current);
    return () => { clearTimeout(t1); clearTimeout(t2); ro.disconnect(); };
  },[cards.length, loopLen]);

  // start down-column from middle
  useEffect(()=>{
    if(direction==="down" && loopH>0) posRef.current = loopH/2;
  },[direction, loopH]);

  const animate = useCallback(()=>{
    if(!pausedRef.current && loopH>0){
      posRef.current += SPEED;
      if(posRef.current >= loopH) posRef.current -= loopH;
      if(posRef.current < 0)      posRef.current += loopH;
      if(trackRef.current) trackRef.current.style.transform=`translateY(-${posRef.current}px)`;
    }
    animRef.current = requestAnimationFrame(animate);
  },[SPEED, loopH]);

  useEffect(()=>{
    animRef.current = requestAnimationFrame(animate);
    return ()=>cancelAnimationFrame(animRef.current);
  },[animate]);

  return (
    <div
      style={{overflow:"hidden",height:"100%",padding: mobile ? "0 20px" : undefined}}
      onMouseEnter={()=>{ pausedRef.current=true; }}
      onMouseLeave={()=>{ pausedRef.current=false; }}
    >
      <div ref={trackRef} style={{display:"flex",flexDirection:"column",gap: mobile ? 16 : 12,willChange:"transform"}}>
        {cards.map((t,i)=>(
          <div key={i} style={{borderRadius:20,background:card,border:`1px solid ${bdr}`,padding: mobile ? "24px 24px 20px" : "22px 22px 18px",display:"flex",flexDirection:"column",gap:14,flexShrink:0,position:"relative",overflow:"hidden"}}>

            {/* quote watermark */}
            <div style={{position:"absolute",top:-12,right:8,fontSize:80,fontFamily:"'Instrument Serif',serif",fontStyle:"italic",color:dark?"rgba(200,184,154,0.06)":"rgba(200,184,154,0.12)",lineHeight:1,pointerEvents:"none",userSelect:"none"}}>"</div>

            {/* stars */}
            <div style={{display:"flex",gap:3}}>
              {Array.from({length:5}).map((_,si)=>(
                <svg key={si} width="12" height="12" viewBox="0 0 24 24"
                  fill={si<t.rating?"#c8b89a":"none"}
                  stroke="#c8b89a" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                  <polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"/>
                </svg>
              ))}
            </div>

            {/* review text */}
            <p style={{fontFamily:"'Instrument Serif',serif",fontStyle:"italic",fontSize: mobile ? 16 : 14,color:dark?"rgba(240,237,232,0.85)":"#18150f",lineHeight:1.75,position:"relative",zIndex:1,margin:0}}>
              "{t.review}"
            </p>

            {/* divider */}
            <div style={{height:1,background:bdr}}/>

            {/* client info */}
            <div style={{display:"flex",alignItems:"center",gap:10}}>
              {/* AVATAR — initials on colored circle */}
              <div style={{
                width:34,height:34,borderRadius:"50%",
                background:t.avatarBg||"#c8b89a",
                display:"flex",alignItems:"center",justifyContent:"center",
                flexShrink:0,
                fontSize:11,fontWeight:800,
                color:"#080808",
                letterSpacing:0.5,
                fontFamily:"'Inter',sans-serif",
              }}>
                {t.avatar}
              </div>
              <div style={{flex:1,overflow:"hidden"}}>
                <div style={{fontSize:12,fontWeight:700,color:dark?"#f0ede8":"#18150f",whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{t.name}</div>
                <div style={{fontSize:10,color:t2,marginTop:1}}>{t.role}</div>
              </div>
              <span style={{padding:"2px 8px",borderRadius:100,fontSize:9,fontWeight:700,letterSpacing:0.5,textTransform:"uppercase",background:"rgba(200,184,154,0.1)",color:"#c8b89a",border:"1px solid rgba(200,184,154,0.22)",flexShrink:0,whiteSpace:"nowrap",maxWidth:100,overflow:"hidden",textOverflow:"ellipsis"}}>
                {t.project}
              </span>
            </div>

          </div>
        ))}
      </div>
    </div>
  );
}

