function FabTop(){
  const [show,setShow]=useState(false);
  useEffect(()=>{const h=()=>setShow(window.scrollY>400);window.addEventListener("scroll",h,{passive:true});return()=>window.removeEventListener("scroll",h);},[]);
  return <button className={`fab-top${show?" show":""}`} onClick={()=>window.scrollTo({top:0,behavior:"smooth"})}>{UP}</button>;
}

const CSS=`
  @import url('https://fonts.googleapis.com/css2?family=Instrument+Serif:ital@0;1&family=Inter:wght@300;400;500;600;700;800&display=swap');
  *,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
  html,body{overflow-x:hidden;width:100%;max-width:100%}
  html{scroll-behavior:smooth}
  ::-webkit-scrollbar{display:none;width:0;height:0}
  *{scrollbar-width:none;-ms-overflow-style:none}
  @keyframes blink{0%,100%{opacity:1}50%{opacity:0.2}}
  @keyframes mq{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}
  @keyframes swipe-hint{0%{transform:translateX(0);opacity:1}50%{transform:translateX(-14px);opacity:0.5}100%{transform:translateX(0);opacity:1}}
  .hero-h1{font-size:clamp(40px,7vw,96px)}.hero-italic{font-size:clamp(36px,6.4vw,88px)}.hero-desc{font-size:clamp(13px,1.4vw,15px)}.hero-content{padding:0 56px 80px}
  .btn-solid{padding:12px 28px;border-radius:100px;background:#f0ede8;color:#080808;font-weight:700;font-size:14px;text-decoration:none;display:inline-flex;align-items:center;gap:8px;box-shadow:0 2px 0 rgba(0,0,0,0.35),0 4px 12px rgba(0,0,0,0.25),inset 0 1px 0 rgba(255,255,255,0.9);transition:transform 0.15s ease,box-shadow 0.15s ease;cursor:pointer;position:relative;top:0}
  .btn-solid:hover{transform:translateY(-2px);box-shadow:0 4px 0 rgba(0,0,0,0.35),0 8px 20px rgba(0,0,0,0.3),inset 0 1px 0 rgba(255,255,255,0.9)}
  .btn-solid:active{transform:translateY(1px);box-shadow:0 1px 0 rgba(0,0,0,0.35),0 2px 6px rgba(0,0,0,0.2),inset 0 1px 0 rgba(255,255,255,0.9)}
  .btn-ghost{padding:12px 28px;border-radius:100px;background:rgba(255,255,255,0.05);color:rgba(240,237,232,0.7);font-weight:500;font-size:14px;text-decoration:none;border:1px solid rgba(255,255,255,0.2);display:inline-flex;align-items:center;gap:8px;box-shadow:0 2px 0 rgba(0,0,0,0.3),0 4px 12px rgba(0,0,0,0.15),inset 0 1px 0 rgba(255,255,255,0.08);transition:transform 0.15s ease,box-shadow 0.15s ease,background 0.15s ease,color 0.15s ease;cursor:pointer;position:relative;top:0;backdrop-filter:blur(8px)}
  .btn-ghost:hover{transform:translateY(-2px);background:rgba(255,255,255,0.1);color:rgba(240,237,232,0.95);box-shadow:0 4px 0 rgba(0,0,0,0.3),0 8px 20px rgba(0,0,0,0.2),inset 0 1px 0 rgba(255,255,255,0.12)}
  .btn-ghost:active{transform:translateY(1px);box-shadow:0 1px 0 rgba(0,0,0,0.3),0 2px 6px rgba(0,0,0,0.15),inset 0 1px 0 rgba(255,255,255,0.08)}
  .nav-link:hover{color:#c8b89a !important;background:rgba(255,255,255,0.07) !important}
  .hire-btn{display:block}.hamburger{display:none !important}.nav-links-desktop{display:flex !important}
  .swipe-hint{display:none}.clink-item{min-height:64px}.footer-inner{padding:0 56px}
  .fab-top{display:none;position:fixed;bottom:24px;right:20px;z-index:150;width:44px;height:44px;border-radius:50%;background:#c8b89a;color:#080808;border:none;cursor:pointer;align-items:center;justify-content:center;box-shadow:0 4px 20px rgba(0,0,0,0.3);transition:transform 0.2s,opacity 0.3s;opacity:0;pointer-events:none}
  .fab-top.show{opacity:1;pointer-events:auto}
  .testi-hover-text{display:inline}
  .testi-mobile-feed{display:none !important}
  .testi-desktop-wall{display:block}
  /* tactile cards */
  .card-lift{transition:transform 0.2s ease,box-shadow 0.2s ease !important}
  .card-lift:hover{transform:translateY(-4px) !important;box-shadow:0 12px 32px rgba(0,0,0,0.35),0 2px 8px rgba(0,0,0,0.2) !important}
  .card-lift:active{transform:translateY(-1px) !important}
  @media(max-width:1024px){
    .skills-grid{grid-template-columns:repeat(6,1fr) !important}
    .skills-stat{grid-column:span 6 !important}
    .skill-card-0,.skill-card-1,.skill-card-2,.skill-card-3{grid-column:span 3 !important}
    .skill-card-4{grid-column:span 6 !important}
    .testi-wall-grid{grid-template-columns:1fr 1fr 1fr !important}
    .testi-wrap{padding:0 32px !important}
    .testi-header{padding-left:32px !important;padding-right:32px !important}
  }
  @media(max-width:768px){
    .hero-content{padding:0 20px 56px !important}
    .hero-h1{font-size:clamp(28px,8.5vw,60px) !important;letter-spacing:-2px !important}
    .hero-italic{font-size:clamp(24px,7.5vw,54px) !important;letter-spacing:-1px !important}
    .hero-bottom{flex-direction:column !important;align-items:flex-start !important;gap:20px !important}
    .hero-btns{flex-wrap:wrap !important;gap:8px !important}
    .hero-desc{font-size:14px !important;max-width:100% !important}
    .page-section{padding:56px 20px !important}
    .about-grid{grid-template-columns:1fr !important}
    .about-grid3{grid-template-columns:1fr !important}
    .skills-grid{grid-template-columns:1fr !important}
    .skills-stat{grid-column:span 1 !important;flex-direction:column !important;gap:16px !important}
    .skill-card-0,.skill-card-1,.skill-card-2,.skill-card-3,.skill-card-4{grid-column:span 1 !important}
    .services-grid{grid-template-columns:1fr !important}
    .services-cards{grid-template-columns:1fr 1fr !important}
    .contact-grid{grid-template-columns:1fr !important}
    .nav-links-desktop{display:none !important}
    .hamburger{display:flex !important}
    .hire-btn{display:none !important}
    .swipe-hint{display:flex !important}
    .clink-item{padding:18px 20px !important;min-height:72px !important}
    .clink-val{font-size:12px !important;word-break:break-all !important}
    .footer-inner{padding:0 20px !important}
    .fab-top{display:flex !important}
    .testi-mobile-feed{display:block !important}
    .testi-desktop-wall{display:none !important}
    .testi-wrap{padding:0 20px !important}
    .testi-header{padding-left:20px !important;padding-right:20px !important}
    .testi-hover-text{display:none !important}
  }
  @media(max-width:480px){
    .hero-content{padding:0 18px 48px !important}
    .hero-h1{font-size:clamp(26px,9vw,46px) !important;letter-spacing:-1.5px !important}
    .hero-italic{font-size:clamp(22px,8vw,42px) !important}
    .hero-btns{gap:6px !important}
    .services-cards{grid-template-columns:1fr !important}
    .btn-solid,.btn-ghost{font-size:13px !important;padding:10px 18px !important}
    .clink-item{padding:16px 18px !important;min-height:68px !important}
    .testi-wall-grid{grid-template-columns:1fr 1fr !important;gap:10px !important;height:480px !important}
    .testi-wrap{padding:0 16px !important}
    .testi-header{padding-left:16px !important;padding-right:16px !important}
    .footer-inner{padding:0 16px !important}
  }
  @media(max-width:375px){
    .hero-h1{font-size:clamp(24px,8.5vw,40px) !important}
    .hero-italic{font-size:clamp(20px,7.5vw,36px) !important}
    .page-section{padding:48px 16px !important}
    .testi-wall-grid{height:440px !important}
  }
`;

export default function App(){
  const [loaded,setLoaded]=useState(false),[dark,setDark]=useState(true);
  const toggle=()=>setDark(d=>!d);
  return (
    <div style={{background:dark?"#080808":"#f5f1ea",color:dark?"#f0ede8":"#18150f",fontFamily:"'Inter',sans-serif",overflowX:"hidden",overflowY:"auto",minHeight:"100vh",transition:"background 0.4s,color 0.4s",position:"relative",maxWidth:"100vw"}}>
      <style>{CSS}</style>
      {!loaded&&<Loader onDone={()=>setLoaded(true)}/>}
      {loaded&&<><Nav dark={dark} toggleTheme={toggle}/><VideoHero/><Marquee dark={dark}/><About dark={dark}/><WordReveal dark={dark}/><Skills dark={dark}/><Projects dark={dark}/><Services dark={dark}/><Testimonials dark={dark}/><Contact dark={dark}/><Footer dark={dark} toggleTheme={toggle}/><FabTop/></>}
    </div>
  );
}